text:
{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "item": "공개 릴리스 목표일은 Smoke 테스트 통과 시 금요일 15:00 KST로 확정됨."
      },
      {
        "item": "packageName mismatch 처리: 스크립트 변경으로 무시하지 않음. 계약/설정이 잘못된 경우에만 해당 스크립트 자체를 재검토."
      },
      {
        "item": "Minjun은 금요일 10:00 KST까지 Smoke 테스트를 재실행하고 결과를 공유하기로 함."
      },
      {
        "item": "Doyun은 금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성하기로 함."
      },
      {
        "item": "Hara는 Minjun이 Smoke 결과를 공유한 뒤 생성된 tarball 경로를 확인하기로 함."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "Hara의 `smoke-theme-pack.mjs`에서 packageName mismatch를 무시하도록 변경",
        "result": "거부됨",
        "근거": "조건부 검사 원칙을 유지하고, 계약/설정이 잘못된 경우에만 스크립트를 검토하는 방향으로 확정."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스 가능성(내부 stretch)",
        "status": "공개 릴리스 최종 일정은 아님"
      },
      {
        "goal": "README 설치 단계는 가능하면 목요일까지 리뷰",
        "status": "미확정 내부 권고 수준"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로 사용 가능성",
        "impact": "릴리스 지연"
      },
      {
        "risk": "README 설치 단계가 최신이 아니면 릴리스 노트가 사용자 오해를 유발할 수 있음",
        "impact": "사용자 안내 정확도 하락"
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 stretch 목표(수요일) 언급 여부는 결정되지 않음."
    ],
    "non_decisions": [
      "README 리뷰 담당자 미지정",
      "Hara의 tarball 경로 확인 구체 기한 미지정"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "Smoke 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트(action_items.md) 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun Smoke 결과 게시 후 생성 tarball 경로 확인",
      "due": "Minjun 결과 공유 이후(구체 기한 미정)",
      "status": "확정",
      "source_certainty": "중간"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 최신성 검토",
      "due": "목요일 가능 시",
      "status": "미확정",
      "source_certainty": "중간"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Smoke 테스트 결과를 기준으로 금요일 15:00 KST 공개 릴리스 게이트 충족 여부 확인",
      "packageName mismatch 발생 시 계약/패키지 구성 우선 검증 완료 여부 점검",
      "Hara의 tarball 경로 확인 완료 여부와 배포 산출물 일치 여부 확인",
      "README 설치 단계 검토 담당자/데드라인 확정",
      "최종 릴리스 승인 권한자 지정 및 책임 경계 확정",
      "릴리스 노트에 수요일 stretch 목표를 언급할지 최종 결정"
    ],
    "what_not_to_invent": [
      "고객명, 파트너명, 예산, 보안 사고, 운영 장애, 법무 승인 필요 여부, 미공개 owner, 미공개 deadline, 미확정된 제약 조건"
    ]
  },
  "non_invention_rules": [
    "회의록/액션 항목은 입력된 Raw notes와 public-safe synthetic fixture에서만 유도된 내용만 사용한다.",
    "명시되지 않은 고객, 예산, 보안 인시던트, 프로덕션 장애, 법적 승인, 추가 owner 또는 최종 deadline을 생성하지 않는다.",
    "명시되지 않은 날짜/시간 또는 역할은 '미지정/미확정/기록 없음'으로만 표현한다.",
    "수요일 항목은 내부 stretch로만 처리하고, 이를 공개 확정 일정으로 오인해 기록하지 않는다."
  ]
}
